{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * 用于计算立直麻将半庄终局时的晋级条件
 */
public class MahjongAdvancementCalculator {

    // 规则类型枚举
    enum RuleType {
        M_LEAGUE,      // M-League 规则
        A_RULE,        // 日本职业麻将联盟竞技规则
        WRC,           // 世界立直麻将大赛规则
        SAIKOISEN      // 最高位战规则
    }

    // 玩家类
    static class Player {
        String name;
        String seat;       // 东/南/西/北
        int startTotalPt;  // 开始前总分
        int currentScore;  // 当前分数
        int rank;          // 当前排名
        boolean isOya;     // 是否亲家
        int seatIndex;     // 座位索引 (0-3)

        Player(String name, String seat, int startTotalPt, int currentScore, int seatIndex) {
            this.name = name;
            this.seat = seat;
            this.startTotalPt = startTotalPt;
            this.currentScore = currentScore;
            this.seatIndex = seatIndex;
        }
    }

    // 游戏状态类
    static class GameState {
        String currentOya;           // 当前亲家
        String[] seats = new String[4];  // 座次
        Player[] players = new Player[4];
        int advanceCount;            // 晋级人数 (1/2/3)
        RuleType ruleType;           // 规则类型
        int riichiSticks;            // 供托数
        int honba;                   // 本场数

        // 马点配置
        int[] uma;  // 1st, 2nd, 3rd, 4th
    }

    // 计算结果类
    static class AdvancementCondition {
        String playerName;
        List<String> selfTsumoConditions = new ArrayList<>();
        List<String> ronConditions = new ArrayList<>();  // 荣和别人
        List<String> dealInConditions = new ArrayList<>();  // 放铳给别人
        List<String> dealInTsumoConditions = new ArrayList<>();  // 被别人自摸
        List<String> dangerZones = new ArrayList<>();  // 危险区间
        List<String> ryukyokuConditions = new ArrayList<>();  // 流局条件

        @Override
        public String toString() {
            StringBuilder sb = new StringBuilder();
            sb.append(playerName).append("晋级条件\n");

            if (!selfTsumoConditions.isEmpty()) {
                sb.append("自摸\t").append(String.join(",", selfTsumoConditions)).append("\n");
            }
            sb.append("=============================\n");

            if (!ronConditions.isEmpty()) {
                for (String cond : ronConditions) {
                    sb.append(cond).append("\n");
                }
            }
            sb.append("=============================\n");

            if (!dealInConditions.isEmpty()) {
                for (String cond : dealInConditions) {
                    sb.append(cond).append("\n");
                }
            }
            sb.append("=============================\n");

            if (!dealInTsumoConditions.isEmpty()) {
                for (String cond : dealInTsumoConditions) {
                    sb.append(cond).append("\n");
                }
            }

            sb.append("\n");
            return sb.toString();
        }
    }

    // 初始化规则马点
    static void initUma(GameState state) {
        switch (state.ruleType) {
            case M_LEAGUE:
                // M-League: +15, +5, -5, -15
                state.uma = new int[]{15, 5, -5, -15};
                break;
            case A_RULE:
                // A规: +15, +5, -5, -15
                state.uma = new int[]{15, 5, -5, -15};
                break;
            case WRC:
                // WRC: +15, +5, -5, -15 (标准)
                state.uma = new int[]{15, 5, -5, -15};
                break;
            case SAIKOISEN:
                // 最高位战: +15, +5, -5, -15
                state.uma = new int[]{15, 5, -5, -15};
                break;
            default:
                state.uma = new int[]{15, 5, -5, -15};
        }
    }

    // 计算最终得分（含马点）
    static int calculateFinalScore(Player player, int rank, GameState state) {
        // 将分数转换为 pt (除以 1000)
        float scorePt = player.currentScore / 1000.0f;
        // 加上马点
        float umaPt = state.uma[rank - 1];
        // 加上开始前总分
        return Math.round((player.startTotalPt + scorePt + umaPt) * 10) / 10;
    }

    // 获取排名（1-4）
    static int getRank(Player player, Player[] players) {
        int rank = 1;
        for (Player p : players) {
            if (p.currentScore > player.currentScore) {
                rank++;
            }
        }
        return rank;
    }

    // 检查是否晋级
    static boolean checkAdvancement(Player player, Player[] players, int rank, GameState state) {
        // 计算所有玩家的最终得分
        int[] finalScores = new int[4];
        int[] ranks = new int[4];

        // 先确定所有玩家的排名
        for (int i = 0; i < 4; i++) {
            int r = 1;
            for (int j = 0; j < 4; j++) {
                if (players[j].currentScore > players[i].currentScore) {
                    r++;
                }
            }
            ranks[i] = r;
        }

        // 计算最终得分
        for (int i = 0; i < 4; i++) {
            finalScores[i] = calculateFinalScore(players[i], ranks[i], state);
        }

        // 计算玩家自己的最终得分
        int playerFinalScore = calculateFinalScore(player, rank, state);

        // 计算有多少玩家排名比当前玩家高
        int betterCount = 0;
        for (int i = 0; i < 4; i++) {
            if (players[i] != player) {
                if (finalScores[i] > playerFinalScore) {
                    betterCount++;
                } else if (finalScores[i] == playerFinalScore) {
                    // 同分时，比较原始分数
                    if (players[i].currentScore > player.currentScore) {
                        betterCount++;
                    }
                }
            }
        }

        // 如果排名在晋级范围内，则晋级
        return betterCount < state.advanceCount;
    }

    // 格式化点数
    static String formatPoints(int points) {
        if (points >= 10000) {
            return (points / 1000) + "万";
        } else if (points >= 1000) {
            return (points / 100) / 10.0 + "千";
        } else {
            return String.valueOf(points);
        }
    }

    // 计算自摸时的点数分配
    static int[] calculateTsumoPayment(int tsumoPoints, boolean isOya, int honba) {
        int[] payments = new int[3];  // 三家支付的点数
        int honbaAdd = honba * 300;

        if (isOya) {
            // 亲家自摸，每家支付相同
            int payment = (tsumoPoints / 6) + honbaAdd;
            payments[0] = payments[1] = payments[2] = payment;
        } else {
            // 子家自摸，亲家支付 2 倍
            int childPayment = (tsumoPoints / 4) + honbaAdd;
            int parentPayment = (tsumoPoints / 2) + honbaAdd;
            payments[0] = parentPayment;  // 亲家
            payments[1] = childPayment;   // 子家 1
            payments[2] = childPayment;   // 子家 2
        }

        return payments;
    }

    // 计算荣和点数
    static int calculateRonPayment(int ronPoints, boolean isOya, int honba) {
        int honbaAdd = honba * 300;
        if (isOya) {
            return ronPoints + honbaAdd * 6;  // 亲家荣和
        } else {
            return ronPoints + honbaAdd * 4;  // 子家荣和
        }
    }

    // 主计算函数
    static List<AdvancementCondition> calculateAdvancement(GameState state) {
        List<AdvancementCondition> results = new ArrayList<>();

        for (Player player : state.players) {
            AdvancementCondition cond = new AdvancementCondition();
            cond.playerName = player.name;

            // 计算当前排名
            int currentRank = getRank(player, state.players);
            boolean currentlyAdvancing = checkAdvancement(player, state.players, currentRank, state);

            // 1. 自摸条件计算
            calculateSelfTsumoConditions(player, state, cond);

            // 2. 荣和条件计算
            calculateRonConditions(player, state, cond);

            // 3. 放铳条件计算
            calculateDealInConditions(player, state, cond);

            // 4. 被自摸条件计算
            calculateDealInTsumoConditions(player, state, cond);

            // 5. 危险区间计算
            calculateDangerZones(player, state, cond);

            results.add(cond);
        }

        return results;
    }

    // 计算自摸条件
    static void calculateSelfTsumoConditions(Player player, GameState state, AdvancementCondition cond) {
        // 尝试不同的自摸点数，找出能晋级的最小点数
        int[] testPoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000};

        List<String> conditions = new ArrayList<>();

        for (int basePoints : testPoints) {
            // 模拟自摸
            Player[] testPlayers = clonePlayers(state.players);
            Player testPlayer = testPlayers[player.seatIndex];

            int[] payments = calculateTsumoPayment(basePoints, player.isOya, state.honba);

            // 加上供托
            int riichiBonus = state.riichiSticks * 1000;

            // 计算得分变化
            testPlayer.currentScore += (payments[0] + payments[1] + payments[2]) + riichiBonus;
            for (int i = 0; i < 4; i++) {
                if (i != player.seatIndex) {
                    testPlayers[i].currentScore -= payments[i < player.seatIndex ? i : (i > player.seatIndex ? i - 1 : 0)];
                }
            }

            // 检查是否晋级
            int newRank = getRank(testPlayer, testPlayers);
            if (checkAdvancement(testPlayer, testPlayers, newRank, state)) {
                conditions.add(formatTsumoPoints(basePoints, player.isOya));
            }
        }

        // 简化条件输出
        if (!conditions.isEmpty()) {
            cond.selfTsumoConditions.add(simplifyConditions(conditions));
        }
    }

    // 计算荣和条件
    static void calculateRonConditions(Player player, GameState state, AdvancementCondition cond) {
        int[] testPoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000, 36000};

        for (Player targetPlayer : state.players) {
            if (targetPlayer == player) continue;

            List<String> conditions = new ArrayList<>();

            for (int basePoints : testPoints) {
                Player[] testPlayers = clonePlayers(state.players);
                Player testPlayer = testPlayers[player.seatIndex];
                Player testTarget = testPlayers[targetPlayer.seatIndex];

                int payment = calculateRonPayment(basePoints, targetPlayer.isOya, state.honba);
                int riichiBonus = state.riichiSticks * 1000;

                testPlayer.currentScore += payment + riichiBonus;
                testTarget.currentScore -= payment;

                int newRank = getRank(testPlayer, testPlayers);
                if (checkAdvancement(testPlayer, testPlayers, newRank, state)) {
                    conditions.add(formatTsumoPoints(basePoints, targetPlayer.isOya));
                }
            }

            if (!conditions.isEmpty()) {
                cond.ronConditions.add(targetPlayer.name + "荣和\t" + simplifyConditions(conditions) + "以上");
            }
        }
    }

    // 计算放铳条件
    static void calculateDealInConditions(Player player, GameState state, AdvancementCondition cond) {
        int[] testPoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000, 36000};

        for (Player targetPlayer : state.players) {
            if (targetPlayer == player) continue;

            List<String> safeConditions = new ArrayList<>();

            for (int basePoints : testPoints) {
                Player[] testPlayers = clonePlayers(state.players);
                Player testPlayer = testPlayers[player.seatIndex];
                Player testTarget = testPlayers[targetPlayer.seatIndex];

                int payment = calculateRonPayment(basePoints, player.isOya, state.honba);
                int riichiBonus = state.riichiSticks * 1000;

                testPlayer.currentScore -= payment;
                testTarget.currentScore += payment + riichiBonus;

                int newRank = getRank(testPlayer, testPlayers);
                if (checkAdvancement(testPlayer, testPlayers, newRank, state)) {
                    safeConditions.add(formatTsumoPoints(basePoints, player.isOya));
                }
            }

            if (!safeConditions.isEmpty()) {
                cond.dealInConditions.add("对" + targetPlayer.name + "放铳\t" + simplifyConditions(safeConditions) + "以下");
            } else {
                cond.dealInConditions.add("对" + targetPlayer.name + "放铳\t任何点数都会失去晋级资格");
            }
        }
    }

    // 计算被自摸条件
    static void calculateDealInTsumoConditions(Player player, GameState state, AdvancementCondition cond) {
        int[] testPoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000};

        for (Player tsumoPlayer : state.players) {
            if (tsumoPlayer == player) continue;

            List<String> safeConditions = new ArrayList<>();

            for (int basePoints : testPoints) {
                Player[] testPlayers = clonePlayers(state.players);
                Player testPlayer = testPlayers[player.seatIndex];
                Player testTsumo = testPlayers[tsumoPlayer.seatIndex];

                int[] payments = calculateTsumoPayment(basePoints, tsumoPlayer.isOya, state.honba);
                int riichiBonus = state.riichiSticks * 1000;

                // 计算玩家支付的点数
                int playerPaymentIndex = 0;
                int totalPayment = 0;
                for (int i = 0; i < 4; i++) {
                    if (i != tsumoPlayer.seatIndex) {
                        if (i == player.seatIndex) {
                            totalPayment = payments[playerPaymentIndex];
                            break;
                        }
                        playerPaymentIndex++;
                    }
                }

                testPlayer.currentScore -= totalPayment;
                testTsumo.currentScore += (payments[0] + payments[1] + payments[2]) + riichiBonus;

                // 其他两家也要支付
                int idx = 0;
                for (int i = 0; i < 4; i++) {
                    if (i != tsumoPlayer.seatIndex && i != player.seatIndex) {
                        testPlayers[i].currentScore -= payments[idx];
                        idx++;
                    }
                }

                int newRank = getRank(testPlayer, testPlayers);
                if (checkAdvancement(testPlayer, testPlayers, newRank, state)) {
                    safeConditions.add(formatTsumoPoints(basePoints, tsumoPlayer.isOya));
                }
            }

            if (!safeConditions.isEmpty()) {
                String suffix = tsumoPlayer.isOya ? "亲家自摸" : "自摸";
                cond.dealInTsumoConditions.add("被" + tsumoPlayer.name + suffix + "\t" + simplifyConditions(safeConditions) + "以下");
            }
        }
    }

    // 计算危险区间
    static void calculateDangerZones(Player player, GameState state, AdvancementCondition cond) {
        // 危险区间：当其他两家发生荣和时，导致玩家失去晋级资格的情况
        int[] testPoints = {1000, 2000, 3000, 4000, 6000, 8000, 12000, 16000, 24000, 36000, 48000, 64000, 96000};

        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 4; j++) {
                if (i == j || state.players[i] == player || state.players[j] == player) continue;

                Player pointGiver = state.players[i];
                Player pointReceiver = state.players[j];

                for (int basePoints : testPoints) {
                    Player[] testPlayers = clonePlayers(state.players);
                    Player testPlayer = testPlayers[player.seatIndex];
                    Player testGiver = testPlayers[pointGiver.seatIndex];
                    Player testReceiver = testPlayers[pointReceiver.seatIndex];

                    int payment = calculateRonPayment(basePoints, pointGiver.isOya, state.honba);
                    int riichiBonus = state.riichiSticks * 1000;

                    testGiver.currentScore -= payment;
                    testReceiver.currentScore += payment + riichiBonus;

                    int newRank = getRank(testPlayer, testPlayers);
                    boolean wasAdvancing = checkAdvancement(player, state.players, getRank(player, state.players), state);
                    boolean nowAdvancing = checkAdvancement(testPlayer, testPlayers, newRank, state);

                    if (wasAdvancing && !nowAdvancing) {
                        cond.dangerZones.add(pointGiver.name + "点" + pointReceiver.name + "\t" + formatTsumoPoints(basePoints, pointGiver.isOya) + "以上会丢晋级资格");
                        break;  // 找到最小危险点数即可
                    }
                }
            }
        }
    }

    // 简化和合并条件
    static String simplifyConditions(List<String> conditions) {
        if (conditions.isEmpty()) return "无法晋级";

        // 去重
        Set<String> unique = new LinkedHashSet<>(conditions);
        List<String> uniqueList = new ArrayList<>(unique);

        if (uniqueList.size() == 1) {
            return uniqueList.get(0);
        }

        // 尝试找出范围
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < uniqueList.size(); i++) {
            sb.append(uniqueList.get(i));
            if (i < uniqueList.size() - 1) {
                sb.append(",");
            }
        }
        return sb.toString();
    }

    // 格式化自摸点数显示
    static String formatTsumoPoints(int basePoints, boolean isOya) {
        if (isOya) {
            // 亲家
            int childPay = basePoints / 6;
            if (basePoints == 100) return "100 点";
            if (basePoints == 300) return "300・500";
            if (basePoints == 400) return "400・700";
            if (basePoints == 500) return "500・1000";
            if (basePoints >= 2000) {
                int allPay = basePoints / 2;
                return allPay + "all";
            }
            return childPay + "・" + (childPay * 2);
        } else {
            // 子家
            int childPay = basePoints / 4;
            int parentPay = basePoints / 2;
            if (basePoints == 100) return "100 点";
            if (basePoints == 300) return "300・500";
            if (basePoints == 400) return "400・700";
            if (basePoints == 500) return "500・1000";
            if (basePoints >= 2000) {
                if (parentPay == childPay * 2) {
                    return childPay + "・" + parentPay;
                }
                return childPay + "・" + parentPay;
            }
            return childPay + "・" + parentPay;
        }
    }

    // 克隆玩家数组
    static Player[] clonePlayers(Player[] players) {
        Player[] clone = new Player[4];
        for (int i = 0; i < 4; i++) {
            clone[i] = new Player(
                players[i].name,
                players[i].seat,
                players[i].startTotalPt,
                players[i].currentScore,
                players[i].seatIndex
            );
            clone[i].isOya = players[i].isOya;
        }
        return clone;
    }

    // 解析输入
    static GameState parseInput(String[] lines) {
        GameState state = new GameState();

        Map<String, String> paramMap = new HashMap<>();
        for (String line : lines) {
            line = line.trim();
            if (line.isEmpty() || line.startsWith("#")) continue;

            String[] parts = line.split("[:：]", 2);
            if (parts.length == 2) {
                paramMap.put(parts[0].trim(), parts[1].trim());
            }
        }

        // 解析当前亲家
        state.currentOya = paramMap.getOrDefault("当前亲家", "东");

        // 解析座次
        String seatsStr = paramMap.getOrDefault("座次", "东 南 西 北");
        state.seats = seatsStr.split("\\s+");

        // 解析名字
        String namesStr = paramMap.getOrDefault("名字", "玩家 1 玩家 2 玩家 3 玩家 4");
        String[] names = namesStr.split("\\s+");

        // 解析开始前总分
        String startPtStr = paramMap.getOrDefault("开始前总分", "0 0 0 0");
        String[] startPts = startPtStr.split("\\s+");

        // 解析当前分数
        String currentScoreStr = paramMap.getOrDefault("当前分数", "25000 25000 25000 25000");
        String[] currentScores = currentScoreStr.split("\\s+");

        // 解析晋级条件
        state.advanceCount = Integer.parseInt(paramMap.getOrDefault("晋级条件", "2"));

        // 解析规则
        String ruleStr = paramMap.getOrDefault("规则", "M-league").toLowerCase();
        if (ruleStr.contains("m-league") || ruleStr.contains("mleague")) {
            state.ruleType = RuleType.M_LEAGUE;
        } else if (ruleStr.contains("a 规") || ruleStr.contains("a-rule") || ruleStr.contains("arule")) {
            state.ruleType = RuleType.A_RULE;
        } else if (ruleStr.contains("wrc")) {
            state.ruleType = RuleType.WRC;
        } else if (ruleStr.contains("最高位") || ruleStr.contains("saikouisen")) {
            state.ruleType = RuleType.SAIKOISEN;
        } else {
            state.ruleType = RuleType.M_LEAGUE;
        }

        // 解析供托
        state.riichiSticks = Integer.parseInt(paramMap.getOrDefault("供托", "0"));

        // 解析本场
        state.honba = Integer.parseInt(paramMap.getOrDefault("本场", "0"));

        // 初始化马点
        initUma(state);

        // 创建玩家
        for (int i = 0; i < 4; i++) {
            state.players[i] = new Player(
                names[i],
                state.seats[i],
                (int)(Double.parseDouble(startPts[i]) * 10),  // 转换为整数存储
                Integer.parseInt(currentScores[i]),
                i
            );
            state.players[i].isOya = state.currentOya.equals(state.seats[i]);
        }

        return state;
    }

    // 生成流局分支一览
    static String generateRyukyokuReport(Player[] players, GameState state) {
        StringBuilder sb = new StringBuilder();
        sb.append("【听牌分支一览】\n");

        // 16 种听牌组合
        String[] playerNames = new String[4];
        for (int i = 0; i < 4; i++) {
            playerNames[i] = players[i].name;
        }

        // 简化处理：假设当前排名靠前的玩家听牌后能晋级
        int[] currentRanks = new int[4];
        for (int i = 0; i < 4; i++) {
            currentRanks[i] = getRank(players[i], players);
        }

        // 找出当前能晋级的玩家
        List<String> currentlyAdvancing = new ArrayList<>();
        for (int i = 0; i < 4; i++) {
            if (currentRanks[i] <= state.advanceCount) {
                currentlyAdvancing.add(playerNames[i]);
            }
        }

        // 生成各种听牌情况
        String[] patterns = {
            "全员未听牌",
            "全员听牌",
            playerNames[0] + "一人听牌",
            playerNames[1] + "一人听牌",
            playerNames[2] + "一人听牌",
            playerNames[3] + "一人听牌",
            playerNames[0] + "一人未听牌",
            playerNames[1] + "一人未听牌",
            playerNames[2] + "一人未听牌",
            playerNames[3] + "一人未听牌",
            playerNames[0] + "、" + playerNames[1] + "听牌",
            playerNames[0] + "、" + playerNames[2] + "听牌",
            playerNames[0] + "、" + playerNames[3] + "听牌",
            playerNames[1] + "、" + playerNames[2] + "听牌",
            playerNames[1] + "、" + playerNames[3] + "听牌",
            playerNames[2] + "、" + playerNames[3] + "听牌"
        };

        for (String pattern : patterns) {
            sb.append(pattern).append(":");

            // 简化处理：输出当前能晋级的玩家
            sb.append("[").append(String.join(", ", currentlyAdvancing)).append("]晋级");

            // 特殊情况：如果最后一名听牌，可能继续
            if (pattern.contains(playerNames[3]) && pattern.contains("听牌") && !pattern.contains("未听牌")) {
                sb.append("，但").append(playerNames[3]).append("听牌而继续");
            }

            sb.append("\n");
        }

        return sb.toString();
    }

    public static void main(String[] args) {
        try {
            // 从标准输入或文件读取
            List<String> lines = new ArrayList<>();

            if (args.length > 0) {
                // 从文件读取
                BufferedReader br = new BufferedReader(new FileReader(args[0]));
                String line;
                while ((line = br.readLine()) != null) {
                    lines.add(line);
                }
                br.close();
            } else {
                // 从标准输入读取
                BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
                String line;
                System.out.println("请输入麻将状态（输入空行结束）：");
                while ((line = br.readLine()) != null && !line.trim().isEmpty()) {
                    lines.add(line);
                }
            }

            if (lines.isEmpty()) {
                System.out.println("错误：没有输入数据");
                return;
            }

            // 解析输入
            GameState state = parseInput(lines.toArray(new String[0]));

            // 计算晋级条件
            List<AdvancementCondition> results = calculateAdvancement(state);

            // 输出结果
            System.out.println("===========================================");
            System.out.println("立直麻将晋级条件计算器");
            System.out.println("===========================================");
            System.out.println("规则：" + state.ruleType);
            System.out.println("晋级人数：" + state.advanceCount + "人");
            System.out.println("供托：" + state.riichiSticks + "本");
            System.out.println("本场：" + state.honba + "本局");
            System.out.println("===========================================\n");

            for (AdvancementCondition cond : results) {
                System.out.print(cond);
                System.out.println(cond.playerName + "危险区间:");
                if (cond.dangerZones.isEmpty()) {
                    System.out.println("无危险区间");
                } else {
                    for (String dz : cond.dangerZones) {
                        System.out.println(dz);
                    }
                }
                System.out.println();
            }

            // 输出流局分支
            System.out.println(generateRyukyokuReport(state.players, state));

        } catch (Exception e) {
            System.err.println("错误：" + e.getMessage());
            e.printStackTrace();
        }
    }
