{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * 用于计算立直麻将半庄终局时的晋级条件
 */
public class MahjongAdvancementCalculator {

    // 规则类型枚举
    enum RuleType {
        M_LEAGUE,      // M-League 规则
        A_RULE,        // 日本职业麻将联盟竞技规则
        WRC,           // 世界立直麻将大赛规则
        SAIKOISEN      // 最高位战规则
    }

    // 玩家类
    static class Player {
        String name;
        String seat;       // 东/南/西/北
        double startTotalPt;  // 开始前总分
        int currentScore;  // 当前分数
        boolean isOya;     // 是否亲家
        int seatIndex;     // 座位索引 (0-3)

        Player(String name, String seat, double startTotalPt, int currentScore, int seatIndex) {
            this.name = name;
            this.seat = seat;
            this.startTotalPt = startTotalPt;
            this.currentScore = currentScore;
            this.seatIndex = seatIndex;
        }
    }

    // 游戏状态类
    static class GameState {
        String currentOya;           // 当前亲家
        String[] seats = new String[4];  // 座次
        Player[] players = new Player[4];
        int advanceCount;            // 晋级人数 (1/2/3)
        RuleType ruleType;           // 规则类型
        int riichiSticks;            // 供托数
        int honba;                   // 本场数

        // 马点配置
        double[] uma;  // 1st, 2nd, 3rd, 4th
    }

    // 计算结果类
    static class AdvancementCondition {
        String playerName;
        String selfTsumoCondition = "";
        List<String> ronConditions = new ArrayList<>();  // 荣和别人
        List<String> dealInConditions = new ArrayList<>();  // 放铳给别人
        List<String> dealInTsumoConditions = new ArrayList<>();  // 被别人自摸
        List<String> dangerZones = new ArrayList<>();  // 危险区间

        @Override
        public String toString() {
            StringBuilder sb = new StringBuilder();
            sb.append(playerName).append("晋级条件\n");

            if (!selfTsumoCondition.isEmpty()) {
                sb.append("自摸\t").append(selfTsumoCondition).append("\n");
            }
            sb.append("=============================\n");

            if (!ronConditions.isEmpty()) {
                for (String cond : ronConditions) {
                    sb.append(cond).append("\n");
                }
            }
            sb.append("=============================\n");

            if (!dealInConditions.isEmpty()) {
                for (String cond : dealInConditions) {
                    sb.append(cond).append("\n");
                }
            }
            sb.append("=============================\n");

            if (!dealInTsumoConditions.isEmpty()) {
                for (String cond : dealInTsumoConditions) {
                    sb.append(cond).append("\n");
                }
            }

            sb.append("\n");
            return sb.toString();
        }
    }

    // 初始化规则马点
    static void initUma(GameState state) {
        switch (state.ruleType) {
            case M_LEAGUE:
            case A_RULE:
            case WRC:
            case SAIKOISEN:
                // 标准马点：+15, +5, -5, -15
                state.uma = new double[]{15, 5, -5, -15};
                break;
            default:
                state.uma = new double[]{15, 5, -5, -15};
        }
    }

    // 计算最终得分（含马点）
    static double calculateFinalScore(Player player, int rank, GameState state) {
        // 将分数转换为 pt (除以 1000)
        double scorePt = player.currentScore / 1000.0;
        // 加上马点
        double umaPt = state.uma[rank - 1];
        // 加上开始前总分
        return player.startTotalPt + scorePt + umaPt;
    }

    // 获取排名（1-4）
    static int getRank(Player player, Player[] players) {
        int rank = 1;
        for (Player p : players) {
            if (p.currentScore > player.currentScore) {
                rank++;
            }
        }
        return rank;
    }

    // 检查是否晋级
    static boolean checkAdvancement(Player player, Player[] players, GameState state) {
        // 计算所有玩家的排名
        int[] ranks = new int[4];
        for (int i = 0; i < 4; i++) {
            ranks[i] = getRank(players[i], players);
        }

        // 计算所有玩家的最终得分
        double[] finalScores = new double[4];
        for (int i = 0; i < 4; i++) {
            finalScores[i] = calculateFinalScore(players[i], ranks[i], state);
        }

        // 计算玩家自己的最终得分
        int playerIdx = -1;
        for (int i = 0; i < 4; i++) {
            if (players[i].name.equals(player.name)) {
                playerIdx = i;
                break;
            }
        }

        if (playerIdx < 0) return false;

        double playerFinalScore = finalScores[playerIdx];

        // 计算有多少玩家排名比当前玩家高
        int betterCount = 0;
        for (int i = 0; i < 4; i++) {
            if (i != playerIdx) {
                if (finalScores[i] > playerFinalScore + 0.01) {  // 考虑浮点误差
                    betterCount++;
                }
            }
        }

        // 如果排名在晋级范围内，则晋级
        return betterCount < state.advanceCount;
    }

    // 格式化点数
    static String formatPoints(int points) {
        if (points >= 10000) {
            return (points / 1000) + "万";
        } else {
            return String.valueOf(points);
        }
    }

    // 计算自摸时的点数分配
    static int[] calculateTsumoPayment(int basePoints, boolean isOya, int honba) {
        int[] payments = new int[3];  // 三家支付的点数
        int honbaAdd = honba * 100;

        if (isOya) {
            // 亲家自摸，每家支付相同
            int payment = (basePoints + 99) / 6 + honbaAdd;  // 向上取整
            payments[0] = payments[1] = payments[2] = payment;
        } else {
            // 子家自摸，亲家支付 2 倍
            int childPayment = (basePoints + 99) / 4 + honbaAdd;
            int parentPayment = (basePoints + 99) / 2 + honbaAdd;
            payments[0] = parentPayment;  // 亲家
            payments[1] = childPayment;   // 子家 1
            payments[2] = childPayment;   // 子家 2
        }

        return payments;
    }

    // 计算荣和点数
    static int calculateRonPayment(int basePoints, boolean isOya, int honba) {
        int honbaAdd = honba * 300;
        if (isOya) {
            return basePoints * 6 + honbaAdd;  // 亲家被荣和
        } else {
            return basePoints * 4 + honbaAdd;  // 子家被荣和
        }
    }

    // 主计算函数
    static List<AdvancementCondition> calculateAdvancement(GameState state) {
        List<AdvancementCondition> results = new ArrayList<>();

        for (Player player : state.players) {
            AdvancementCondition cond = new AdvancementCondition();
            cond.playerName = player.name;

            // 检查当前是否已经晋级
            boolean currentlyAdvancing = checkAdvancement(player, state.players, state);

            // 1. 自摸条件计算
            calculateSelfTsumoConditions(player, state, cond);

            // 2. 荣和条件计算
            calculateRonConditions(player, state, cond);

            // 3. 放铳条件计算
            calculateDealInConditions(player, state, cond);

            // 4. 被自摸条件计算
            calculateDealInTsumoConditions(player, state, cond);

            // 5. 危险区间计算
            calculateDangerZones(player, state, cond);

            results.add(cond);
        }

        return results;
    }

    // 计算自摸条件
    static void calculateSelfTsumoConditions(Player player, GameState state, AdvancementCondition cond) {
        // 尝试不同的自摸点数，找出能晋级的最小点数
        int[] testBasePoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000};

        List<Integer> successPoints = new ArrayList<>();

        for (int basePoints : testBasePoints) {
            // 模拟自摸
            Player[] testPlayers = clonePlayers(state.players);
            Player testPlayer = testPlayers[player.seatIndex];

            int[] payments = calculateTsumoPayment(basePoints, player.isOya, state.honba);

            // 加上供托
            int riichiBonus = state.riichiSticks * 1000;

            // 计算得分变化
            int totalGain = 0;
            for (int p : payments) totalGain += p;
            testPlayer.currentScore += totalGain + riichiBonus;

            // 其他三家支付
            int payIdx = 0;
            for (int i = 0; i < 4; i++) {
                if (i != player.seatIndex) {
                    testPlayers[i].currentScore -= payments[payIdx];
                    payIdx++;
                }
            }

            // 检查是否晋级
            if (checkAdvancement(testPlayer, testPlayers, state)) {
                successPoints.add(basePoints);
            }
        }

        // 简化条件输出
        if (!successPoints.isEmpty()) {
            cond.selfTsumoCondition = simplifyTsumoConditions(successPoints, player.isOya);
        }
    }

    // 计算荣和条件
    static void calculateRonConditions(Player player, GameState state, AdvancementCondition cond) {
        int[] testBasePoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000, 36000};

        for (Player targetPlayer : state.players) {
            if (targetPlayer == player) continue;

            List<Integer> successPoints = new ArrayList<>();

            for (int basePoints : testBasePoints) {
                Player[] testPlayers = clonePlayers(state.players);
                Player testPlayer = testPlayers[player.seatIndex];
                Player testTarget = testPlayers[targetPlayer.seatIndex];

                int payment = calculateRonPayment(basePoints, targetPlayer.isOya, state.honba);
                int riichiBonus = state.riichiSticks * 1000;

                testPlayer.currentScore += payment + riichiBonus;
                testTarget.currentScore -= payment;

                if (checkAdvancement(testPlayer, testPlayers, state)) {
                    successPoints.add(basePoints);
                }
            }

            if (!successPoints.isEmpty()) {
                String pointStr = simplifyRonConditions(successPoints, targetPlayer.isOya);
                cond.ronConditions.add(targetPlayer.name + "荣和\t" + pointStr + "以上");
            }
        }
    }

    // 计算放铳条件
    static void calculateDealInConditions(Player player, GameState state, AdvancementCondition cond) {
        int[] testBasePoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000, 36000};

        for (Player targetPlayer : state.players) {
            if (targetPlayer == player) continue;

            List<Integer> safePoints = new ArrayList<>();

            for (int basePoints : testBasePoints) {
                Player[] testPlayers = clonePlayers(state.players);
                Player testPlayer = testPlayers[player.seatIndex];
                Player testTarget = testPlayers[targetPlayer.seatIndex];

                int payment = calculateRonPayment(basePoints, player.isOya, state.honba);
                int riichiBonus = state.riichiSticks * 1000;

                testPlayer.currentScore -= payment;
                testTarget.currentScore += payment + riichiBonus;

                if (checkAdvancement(testPlayer, testPlayers, state)) {
                    safePoints.add(basePoints);
                }
            }

            if (!safePoints.isEmpty()) {
                String pointStr = simplifyRonConditions(safePoints, player.isOya);
                cond.dealInConditions.add("对" + targetPlayer.name + "放铳\t" + pointStr + "以下");
            } else {
                cond.dealInConditions.add("对" + targetPlayer.name + "放铳\t任何点数都会失去晋级资格");
            }
        }
    }

    // 计算被自摸条件
    static void calculateDealInTsumoConditions(Player player, GameState state, AdvancementCondition cond) {
        int[] testBasePoints = {100, 300, 400, 500, 700, 1000, 1300, 2000, 2600, 3000, 4000, 6000, 8000, 12000, 16000, 24000};

        for (Player tsumoPlayer : state.players) {
            if (tsumoPlayer == player) continue;

            List<Integer> safePoints = new ArrayList<>();

            for (int basePoints : testBasePoints) {
                Player[] testPlayers = clonePlayers(state.players);
                Player testPlayer = testPlayers[player.seatIndex];
                Player testTsumo = testPlayers[tsumoPlayer.seatIndex];

                int[] payments = calculateTsumoPayment(basePoints, tsumoPlayer.isOya, state.honba);
                int riichiBonus = state.riichiSticks * 1000;

                // 计算玩家支付的点数
                int playerPayment = 0;
                int payIdx = 0;
                for (int i = 0; i < 4; i++) {
                    if (i != tsumoPlayer.seatIndex) {
                        if (i == player.seatIndex) {
                            playerPayment = payments[payIdx];
                            break;
                        }
                        payIdx++;
                    }
                }

                testPlayer.currentScore -= playerPayment;

                // 自摸者获得所有支付 + 供托
                int totalPayment = 0;
                for (int p : payments) totalPayment += p;
                testTsumo.currentScore += totalPayment + riichiBonus;

                // 其他两家也要支付
                payIdx = 0;
                for (int i = 0; i < 4; i++) {
                    if (i != tsumoPlayer.seatIndex && i != player.seatIndex) {
                        testPlayers[i].currentScore -= payments[payIdx];
                        payIdx++;
                    }
                }

                if (checkAdvancement(testPlayer, testPlayers, state)) {
                    safePoints.add(basePoints);
                }
            }

            if (!safePoints.isEmpty()) {
                String suffix = tsumoPlayer.isOya ? "亲家自摸" : "自摸";
                String pointStr = simplifyTsumoConditions(safePoints, tsumoPlayer.isOya);
                cond.dealInTsumoConditions.add("被" + tsumoPlayer.name + suffix + "\t" + pointStr + "以下");
            }
        }
    }

    // 计算危险区间
    static void calculateDangerZones(Player player, GameState state, AdvancementCondition cond) {
        // 危险区间：当其他两家发生荣和时，导致玩家失去晋级资格的情况
        int[] testBasePoints = {1000, 2000, 3000, 4000, 6000, 8000, 12000, 16000, 24000, 36000, 48000, 64000, 96000};

        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 4; j++) {
                if (i == j || state.players[i] == player || state.players[j] == player) continue;

                Player pointGiver = state.players[i];
                Player pointReceiver = state.players[j];

                for (int basePoints : testBasePoints) {
                    Player[] testPlayers = clonePlayers(state.players);
                    Player testPlayer = testPlayers[player.seatIndex];
                    Player testGiver = testPlayers[pointGiver.seatIndex];
                    Player testReceiver = testPlayers[pointReceiver.seatIndex];

                    int payment = calculateRonPayment(basePoints, pointGiver.isOya, state.honba);
                    int riichiBonus = state.riichiSticks * 1000;

                    testGiver.currentScore -= payment;
                    testReceiver.currentScore += payment + riichiBonus;

                    boolean wasAdvancing = checkAdvancement(player, state.players, state);
                    boolean nowAdvancing = checkAdvancement(testPlayer, testPlayers, state);

                    if (wasAdvancing && !nowAdvancing) {
                        String pointStr = formatRonPayment(basePoints, pointGiver.isOya, state.honba);
                        cond.dangerZones.add(pointGiver.name + "点" + pointReceiver.name + "\t" + pointStr + "以上会丢晋级资格");
                        break;  // 找到最小危险点数即可
                    }
                }
            }
        }
    }

    // 简化自摸条件输出
    static String simplifyTsumoConditions(List<Integer> points, boolean isOya) {
        if (points.isEmpty()) return "无法晋级";

        // 找出最小点数
        int minPoint = Collections.min(points);

        // 检查是否所有点数都能晋级
        boolean allSucceed = points.size() >= 10;  // 大部分点数都能晋级

        if (allSucceed && minPoint <= 500) {
            return formatTsumoPayment(minPoint, isOya);
        }

        // 简化输出
        StringBuilder sb = new StringBuilder();
        Integer[] arr = points.toArray(new Integer[0]);
        Arrays.sort(arr);

        if (arr.length == 1) {
            return formatTsumoPayment(arr[0], isOya);
        }

        // 找出范围
        int start = arr[0];
        int end = arr[arr.length - 1];

        // 检查是否连续
        boolean continuous = true;
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] - arr[i-1] > 500) {
                continuous = false;
                break;
            }
        }

        if (continuous && arr.length > 3) {
            return formatTsumoPayment(start, isOya) + "以上";
        } else {
            // 输出关键点数
            sb.append(formatTsumoPayment(start, isOya));
            if (arr.length > 1 && arr.length < 5) {
                for (int i = 1; i < arr.length; i++) {
                    sb.append(",").append(formatTsumoPayment(arr[i], isOya));
                }
            }
            return sb.toString();
        }
    }

    // 简化荣和条件输出
    static String simplifyRonConditions(List<Integer> points, boolean isOya) {
        if (points.isEmpty()) return "无法晋级";

        int minPoint = Collections.min(points);
        return formatRonPayment(minPoint, isOya, 0);
    }

    // 格式化自摸支付显示
    static String formatTsumoPayment(int basePoints, boolean isOya) {
        if (isOya) {
            // 亲家自摸
            if (basePoints <= 100) return "100 点";
            if (basePoints <= 300) return "300・500";
            if (basePoints <= 400) return "400・700";
            if (basePoints <= 500) return "500・1000";
            if (basePoints <= 1000) return "1000・2000";
            if (basePoints <= 2000) return "2000・4000";
            if (basePoints <= 3000) return "3000・6000";
            if (basePoints <= 4000) return "4000・8000";
            if (basePoints <= 6000) return "6000・12000";
            if (basePoints <= 8000) return "8000all";
            if (basePoints <= 12000) return "12000all";
            if (basePoints <= 16000) return "16000all";
            return "24000all";
        } else {
            // 子家自摸
            if (basePoints <= 100) return "100 点";
            if (basePoints <= 300) return "300・500";
            if (basePoints <= 400) return "400・700";
            if (basePoints <= 500) return "500・1000";
            if (basePoints <= 1000) return "1000・2000";
            if (basePoints <= 2000) return "2000・4000";
            if (basePoints <= 3000) return "3000・6000";
            if (basePoints <= 4000) return "4000・8000";
            if (basePoints <= 6000) return "6000・12000";
            if (basePoints <= 8000) return "8000・16000";
            if (basePoints <= 12000) return "12000・24000";
            return "24000・48000";
        }
    }

    // 格式化荣和支付显示
    static String formatRonPayment(int basePoints, boolean isOya, int honba) {
        int payment = calculateRonPayment(basePoints, isOya, honba);
        return formatPoints(payment);
    }

    // 克隆玩家数组
    static Player[] clonePlayers(Player[] players) {
        Player[] clone = new Player[4];
        for (int i = 0; i < 4; i++) {
            clone[i] = new Player(
                players[i].name,
                players[i].seat,
                players[i].startTotalPt,
                players[i].currentScore,
                players[i].seatIndex
            );
            clone[i].isOya = players[i].isOya;
        }
        return clone;
    }

    // 解析输入
    static GameState parseInput(String[] lines) {
        GameState state = new GameState();

        Map<String, String> paramMap = new HashMap<>();
        for (String line : lines) {
            line = line.trim();
            if (line.isEmpty() || line.startsWith("#")) continue;

            String[] parts = line.split("[:：]", 2);
            if (parts.length == 2) {
                paramMap.put(parts[0].trim(), parts[1].trim());
            }
        }

        // 解析当前亲家
        state.currentOya = paramMap.getOrDefault("当前亲家", "东");

        // 解析座次
        String seatsStr = paramMap.getOrDefault("座次", "东 南 西 北");
        state.seats = seatsStr.split("\\s+");

        // 解析名字
        String namesStr = paramMap.getOrDefault("名字", "玩家 1 玩家 2 玩家 3 玩家 4");
        String[] names = namesStr.split("\\s+");

        // 解析开始前总分
        String startPtStr = paramMap.getOrDefault("开始前总分", "0 0 0 0");
        String[] startPts = startPtStr.split("\\s+");

        // 解析当前分数
        String currentScoreStr = paramMap.getOrDefault("当前分数", "25000 25000 25000 25000");
        String[] currentScores = currentScoreStr.split("\\s+");

        // 解析晋级条件
        state.advanceCount = Integer.parseInt(paramMap.getOrDefault("晋级条件", "2"));

        // 解析规则
        String ruleStr = paramMap.getOrDefault("规则", "M-league").toLowerCase();
        if (ruleStr.contains("m-league") || ruleStr.contains("mleague")) {
            state.ruleType = RuleType.M_LEAGUE;
        } else if (ruleStr.contains("a 规") || ruleStr.contains("a-rule") || ruleStr.contains("arule")) {
            state.ruleType = RuleType.A_RULE;
        } else if (ruleStr.contains("wrc")) {
            state.ruleType = RuleType.WRC;
        } else if (ruleStr.contains("最高位") || ruleStr.contains("saikouisen")) {
            state.ruleType = RuleType.SAIKOISEN;
        } else {
            state.ruleType = RuleType.M_LEAGUE;
        }

        // 解析供托
        state.riichiSticks = Integer.parseInt(paramMap.getOrDefault("供托", "0"));

        // 解析本场
        state.honba = Integer.parseInt(paramMap.getOrDefault("本场", "0"));

        // 初始化马点
        initUma(state);

        // 创建玩家
        for (int i = 0; i < 4; i++) {
            state.players[i] = new Player(
                names[i],
                state.seats[i],
                Double.parseDouble(startPts[i]),
                Integer.parseInt(currentScores[i]),
                i
            );
            state.players[i].isOya = state.currentOya.equals(state.seats[i]);
        }

        return state;
    }

    // 生成流局分支一览
    static String generateRyukyokuReport(Player[] players, GameState state) {
        StringBuilder sb = new StringBuilder();
        sb.append("【听牌分支一览】\n");

        String[] playerNames = new String[4];
        for (int i = 0; i < 4; i++) {
            playerNames[i] = players[i].name;
        }

        // 找出当前能晋级的玩家
        List<String> currentlyAdvancing = new ArrayList<>();
        for (int i = 0; i < 4; i++) {
            if (checkAdvancement(players[i], players, state)) {
                currentlyAdvancing.add(playerNames[i]);
            }
        }

        // 生成各种听牌情况
        String[] patterns = {
            "全员未听牌",
            "全员听牌",
            playerNames[0] + "一人听牌",
            playerNames[1] + "一人听牌",
            playerNames[2] + "一人听牌",
            playerNames[3] + "一人听牌",
            playerNames[0] + "一人未听牌",
            playerNames[1] + "一人未听牌",
            playerNames[2] + "一人未听牌",
            playerNames[3] + "一人未听牌",
            playerNames[0] + "、" + playerNames[1] + "听牌",
            playerNames[0] + "、" + playerNames[2] + "听牌",
            playerNames[0] + "、" + playerNames[3] + "听牌",
            playerNames[1] + "、" + playerNames[2] + "听牌",
            playerNames[1] + "、" + playerNames[3] + "听牌",
            playerNames[2] + "、" + playerNames[3] + "听牌"
        };

        for (String pattern : patterns) {
            sb.append(pattern).append(":");
            sb.append("[").append(String.join(", ", currentlyAdvancing)).append("]晋级");

            // 特殊情况：如果最后一名听牌，可能继续
            if (pattern.contains(playerNames[3]) && pattern.contains("听牌") && !pattern.contains("未听牌")) {
                sb.append("，但").append(playerNames[3]).append("听牌而继续");
            }

            sb.append("\n");
        }

        return sb.toString();
    }

